INSERT INTO catalog_products (id, slug, name, price, session_price, category_id, company_id, thumbnail_url, description, detail) VALUES
  ('96', 'balo-sony-backpack-2-1body-3lens', 'Balo Sony Backpack 2 (1Body, 3Lens)', 50000, 35000, 6, 30, '/assets/catalog/product/96/16355857918742021L10l30T09a23X11.jpg', '<p>- Dùng chứa máy ảnh Sony, ống kính, sạc và các phụ kiện khác....</p><p>- Thiết kế đẹp mắt, hợp thời trang</p><p>- Khóa dây kéo bền chắc</p><p>- Dây đeo bản to, có thể điều chỉnh, được may gia cố vững kèm phần</p>', '<p><span style="color: rgb(153, 153, 153);">Tóm tắt sản phẩm:</span></p><p>- Dùng chứa máy ảnh Sony, ống kính, sạc và các phụ kiện khác....</p><p>- Thiết kế đẹp mắt, hợp thời trang</p><p>- Khóa dây kéo bền chắc</p><p>- Dây đeo bản to, có thể điều chỉnh, được may gia cố vững kèm phần đệm mút êm, thoáng khí, dễ chịu</p><p><br></p>'),
  ('428', 'bo-phong-vai-trang-di-dong-quay-phim-3m6m', 'Bộ phông vải trắng di động quay phim (3m*6m)', 300000, 210000, 6, 23, '/assets/catalog/product/428/175517103868822ba79faed8e4bc64c218b504df48f5e6a1c88b23199d15762.jpg', '<p>Kich thước 3m*6m</p><p>Chiều Cao 3m</p><p>Vải không dệt</p><p>2 chân và thanh ngang</p>', '<p class="ql-align-center"><strong>Phông vải nền Studio</strong></p><p>Phông Vải Studio là một phụ kiện studio thiết bị phòng chụp quan trọng và cần thiết nhất trong mỗi phòng chụp studio. Với thiết kế đơn giản và dễ sử dụng khi bạn đi chụp ngoại cảnh cũng như trong phòng chụp.</p><p>&nbsp;</p><p class="ql-align-center"><img src="https://mayanh24h.com/image/catalog/san-pham/phu-kien-may-anh/thiet-bi-phong-chup/khung-treo-phong/vai-phong-nen-3.jpg"></p><p><br></p>'),
  ('11', 'canon-ef-16-35mm-f4l-is-usm', 'Canon EF 16-35mm f/4L IS USM', 200000, 140000, 5, 9, '/assets/catalog/product/11/16263492441722021u07p15T11C40Y44.jpg', '<ul><li>Chống rung: Có</li><li>Khẩu độ: F/4-22</li><li>Khoảng cách lấy nét gần nhất: 28cm</li><li>Kích thước Filter: 77mm</li></ul><p><br></p>', '<p class="ql-align-justify">Vẫn là những ưu điểm quen thuộc trong thiết kế của dòng Luxury từ Canon,&nbsp;Canon EF 16-35mm f/4L IS USM với vỏ bọc ống kính chống bám bụi, chống vết bẩn, không để lại dấu vân tay. Lớp phủ bảo vệ flo ở bề mặt trước giúp ống kính dễ dàng lau chùi, giữ độ bền cực tốt.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm.jpg" alt="Canon EF 16-35mm f/4L IS USM chính hãng" height="442" width="600"></p><h2 class="ql-align-justify">Ống kính&nbsp;Canon ngàm EF, dải tiêu cự 16-35mm, khẩu độ&nbsp;f/4</h2><p class="ql-align-justify"><a href="https://vjshop.vn/ong-kinh-dslr/canon-ef-16-35mm-f4l-is-usm" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">Canon EF 16-35mm f/4L IS USM</a>&nbsp;được thiết kế cho máy ảnh Canon DSLR full-frame tương đương tiêu cự 25.6 - 56mm khi gắn trên máy có cảm biến APS-C cũng có thể tương thích với dòng lens cao cấp này.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm-2.jpg" alt="Canon EF 16-35mm f/4L IS USM tương thích máy ảnh DSLR" height="401" width="600"></p><p class="ql-align-justify"><a href="https://vjshop.vn/ong-kinh" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">Ống kính</a>&nbsp;có khẩu độ f/4 trên toàn dải zoom cho độ ổn định và chất lượng ảnh đồng nhất tại mỗi tiêu cự. Đảm bảo độ sáng nhất quán cho toàn bộ ảnh chụp ở cùng một bối ảnh trong toàn phạm vi zoom.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm-1.jpg" alt="Canon EF 16-35mm f/4L IS USM tiêu cự thay đổi được" height="409" width="600"></p><h2 class="ql-align-justify">Cấu tạo quang học ống kính&nbsp;Canon EF 16-35mm f/4L IS USM</h2><p class="ql-align-justify">Canon EF 16-35mm f/4L&nbsp;được cấu tạo với 3 thấu kính vi cầu Aspheric, 2 thấu kính tán sắc siêu thấp&nbsp;&nbsp;(UD_ Ultra Low-Dispersion) giúp hạn chế tối đa hiện tượng biến dạng màu, méo các góc ảnh, hiện tượng quang sai cầu ảnh cho ra những bức hình sắc nét, chính xác và có màu ảnh chân thực nhất.</p><p class="ql-align-justify"><a href="https://vjshop.vn/ong-kinh-dslr" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">Ống kính DSLR</a>&nbsp;này&nbsp;có thể hoạt động tốt cả trong điều kiện ánh sáng mạnh nhờ lớp phủ Super Spectra Coating chống lóa và điều kiện ánh sáng yếu nhờ hệ thống ổn định hình ảnh chống rung 4 stops.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm-3.jpg" alt="Cấu tạo quang học Canon EF 16-35mm f/4L IS USM " height="305" width="600"></p><h2 class="ql-align-justify">Hệ thống lấy nét xoay vòng USM</h2><p class="ql-align-justify">Lens được trang bị hệ thống lấy nét trong cùng với vòng lấy nét motor vòng siêu âm USM giúp tăng độ chính xác, giảm thời gian lấy nét đối tượng và không gây ra tiếng ồn. Hệ thống lấy nét bằng tay cũng được cải tiến hơn với thanh đo điều chỉnh khoảng cách lấy nét.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm-4.jpg" alt="Canon EF 16-35mm f/4L IS USM - động cơ lấy nét USM" height="347" width="600"></p><h2 class="ql-align-justify">Tạo ảnh có chất lượng bokeh đẹp mắt</h2><p class="ql-align-justify">Ống kính Canon 16-35mm được cấu tạo từ 09 lá khẩu cho khả năng kiểm soát độ sâu trường ảnh hiệu quả cũng như tăng hiệu suất lấy nét và làm mịn phông nền.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-16-35mm-f4l/anh-mo-ta/ong-kinh-canon-ef-16-35mm-f4l-is-usm-6.jpg" alt="Canon EF 16-35mm f/4L IS USM - ảnh thực tế" height="400" width="600"></p><p><br></p>'),
  ('10', 'canon-ef-17-40mm-f4l-usm-lens-1', 'Canon EF 17-40mm f/4L USM (LENS 1)', 100000, 70000, 5, 9, '/assets/catalog/product/10/16263131227002021L07w15T01T38Z42.jpg', '<ul><li>Chống rung: Không</li><li>Khẩu độ: F/4-22</li><li>Khoảng cách lấy nét gần nhất: 28cm</li><li>Kích thước Filter: 77mm</li></ul><p><br></p>', '<p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-17-40mm-f4l/anh-mo-ta/ong-kinh-canon-ef-17-40mm-f4l-usm.jpg" alt="Canon EF 17-40mm f/4L USM chính hãng" height="447" width="600"></p><h2 class="ql-align-justify">Thiết kế mạnh mẽ, chống chịu thời tiết tốt</h2><p class="ql-align-justify">Ngay từ thiết kế bên ngoài đã có thể nhìn thấy được sự cao cấp của&nbsp;<a href="https://vjshop.vn/ong-kinh-dslr/canon-ef-17-40mm-f4l-usm" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">Canon EF 17-40mm f/4L USM</a>&nbsp;với ngàm EF kim loại chất lượng cao. Vỏ bọc ống kính chất liệu cao cấp cho cảm giác cầm trên tay chắc chắn. Khả năng chống bám bụi, chống nước cũng được coi là một trong những ưu điểm vượt trội giúp chiếc ống kính này có thể hoạt động ổn định trong điều kiện thời tiết khắc nghiệt.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-17-40mm-f4l/anh-mo-ta/ong-kinh-canon-ef-17-40mm-f4l-usm-7.jpg" alt="Canon EF 17-40mm f/4L USM - thiết kế mạnh mẽ" height="399" width="600"></p><h2 class="ql-align-justify">Ống kính Canon EF tiêu cự 17-40mm, khẩu độ&nbsp;f/4L</h2><p class="ql-align-justify">Canon EF 17-40mm được thiết kế dành riêng cho thể loại ảnh phong cảnh, nội thất và kiến trúc hay đơn giản là chụp tập thể đông người trong các buổi kỷ yếu thì đây là ống kính không thể thiếu của các nhiếp ảnh gia chuyên nghiệp.</p><p class="ql-align-justify">Khẩu độ tối đa cố định f/4 với góc zoom 104 độ giúp&nbsp;<a href="https://vjshop.vn/ong-kinh" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">ống kính</a>&nbsp;duy trì được độ sáng trong từng khung hình trong phạm vi toàn bộ góc zoom. Khi đó, ánh sáng yếu hay bối cảnh hẹp cũng không thể làm khó bạn. Đặc biệt Canon EF 17-40mm f/4L USM còn cải thiện hơn những dòng ống kính zoom góc rộng khác ở khả năng khắc phục hiện tượng méo ảnh.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-17-40mm-f4l/anh-mo-ta/ong-kinh-canon-ef-17-40mm-f4l-usm-8.jpg" alt="Canon EF 17-40mm f/4L USM tiêu cự mở rộng" height="400" width="600"></p><h2 class="ql-align-justify">Cấu tạo quang học&nbsp;Canon EF 17-40mm f/4L USM</h2><p class="ql-align-justify">Hình ảnh được chụp ra hạn chế tối đa các viền màu và hiện tượng quang sai màu nhờ hệ thấu kính quang học 12 phần tử. Trong đó, 3 thấu kính super UD giúp giảm tối đã sai sắc màu cho hình ảnh. Tất nhiên với một ống kính cao cấp như Canon EF 17-40mm f/4L USM không thể thiếu được lớp phủ bảo vệ Super Spectra Coatings (SSC) để cải thiện tình trạng bóng mờ&nbsp;khi chụp trong bối cảnh ánh sáng quá mạnh.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-17-40mm-f4l/anh-mo-ta/ong-kinh-canon-ef-17-40mm-f4l-usm-3.jpg" alt="Cấu tạo quang học Canon EF 17-40mm f/4L USM" height="395" width="600"></p><h2 class="ql-align-justify">Hệ thống lấy nét nhanh, chính xác và&nbsp;êm ái</h2><p class="ql-align-justify">Sử dụng công nghệ lấy nét siêu âm USM dạng xoay vòng,&nbsp;<a href="https://vjshop.vn/ong-kinh-dslr" rel="noopener noreferrer" target="_blank" style="color: rgb(0, 109, 154);">ống kính DSLR</a>&nbsp;này giúp cho việc lấy nét toàn thời gian chủ động hơn, nhanh hơn và giảm tiếng ồn tối đa.</p><p class="ql-align-center"><img src="https://cdn.vjshop.vn/ong-kinh/dslr/canon/canon-ef-17-40mm-f4l/anh-mo-ta/ong-kinh-canon-ef-17-40mm-f4l-usm-6.jpg" alt="Canon EF 17-40mm f/4L USM lấy nét nhanh, chính xác" height="400" width="600"></p><p><br></p>'),
  ('197', 'chan-den-inox-jinbei-ck-1-c-stand-chan-1', 'Chân Đèn INOX Jinbei CK-1 C-Stand - CHÂN 1', 100000, 70000, 6, 25, '/assets/catalog/product/197/16394959201762021H12s14T15e32F00.jpg', '<p><span style="color: rgb(68, 68, 68);">- Chiều cao tối đa chân:&nbsp;310 Cm</span></p><p><span style="color: rgb(68, 68, 68);">- Chiều cao tối thiểu:&nbsp;140 Cm</span></p><p><span style="color: rgb(68, 68, 68);">- Độ cao cả tay boom : &gt;3m</span></p><p><span style="color: rgb(68, 68, 68);">- Độ dày ống : 1.5 mm</span></p>', '<p class="ql-align-center"><strong>Chân Đèn INOX Jinbei CK-1 C-Stand</strong></p><p class="ql-align-center"><br></p><p><span style="color: rgb(99, 99, 99);">Chân Đèn&nbsp;</span></p><p><strong style="color: rgb(99, 99, 99);">INOX Jinbei CK-1 C-Stand</strong><span style="color: rgb(99, 99, 99);">&nbsp;là một phụ kiện studio không thể thiếu và là sự lựa chọn hoàn hảo cho các thiết bị phòng chụp trong Studio của bạn. Được thiết kế vô cùng vững chắc, các chi tiết vô cùng sắc nét và kết nối với nhau một cách ăn khớp đến từng chi tiết nhỏ sẽ có khả năng chịu tải trọng lượng của đèn Flash Studio cũng như các thiết bị phòng chụp khác một cách tối đa.</span></p><p class="ql-align-center"><span style="color: rgb(99, 99, 99);"><img src="https://mayanh24h.com/image/catalog/san-pham-2019/chan-may-tripod/jinbei/jinbei-ck-1-inox/jinbei-ck-1-1.jpg"></span></p><p class="ql-align-center"><span style="color: rgb(99, 99, 99);">Chân Đèn&nbsp;</span><strong style="color: rgb(99, 99, 99);">INOX Jinbei CK-1 C-Stand</strong><span style="color: rgb(99, 99, 99);">&nbsp;còn được thiết kế với từng khớp kết nối với nhau rất cứng chắc. Đó sẽ là lựa chọn số 1 để bạn có thể sử dụng cũng như bảo vệ các thiết bị Studio trong phòng chụp của bạn an toàn và hữu ích nhất.<img src="https://mayanh24h.com/image/catalog/san-pham-2019/chan-may-tripod/jinbei/jinbei-ck-1-inox/jinbei-ck-1-5.jpg"></span></p><p><span style="color: rgb(99, 99, 99);">Cấu tạo từ chất liệu Inox cao cấp, chân có thể chịu được sức nặng của các loại đèn Studio và các phụ kiện một cách chắc chắn.</span></p><p><span style="color: rgb(99, 99, 99);">Sử dụng dễ dàng phù hợp trong phòng Studio và có thể gấp gọn lại mang theo trong các sự kiện ngoài trời.</span></p><p class="ql-align-center"><span style="color: rgb(99, 99, 99);">Chiều cao tối đa :&nbsp;240 Cm<img src="https://mayanh24h.com/image/catalog/san-pham-2019/chan-may-tripod/jinbei/jinbei-ck-1-inox/jinbei-ck-1-2.jpg"></span></p><p><span style="color: rgb(99, 99, 99);">Được thiết kế vô cùng bắt mắt,gọn nhẹ, các chi tiết vô cùng sắc nét, có khả năng chịu tải trọng lượng của đèn Flash Studio, Flash Speedlite ,......</span></p><p><span style="color: rgb(99, 99, 99);">Dùng&nbsp;để chụp những sản phẩm nhỏ ở nhiều góc độ khác nhau hoặc kết hợp với các phụ kiện khác trong thiết bị phòng chụp một cách tối đa. Hơn thế nữa Chân Đèn&nbsp;</span><strong style="color: rgb(99, 99, 99);">Flash Jinbei CK-1 C-Stand INOX</strong><span style="color: rgb(99, 99, 99);">&nbsp;còn có thể tháo lắp rất dễ dàng khiến cho việc sử dụng được thuận lợi nhất.&nbsp;</span></p><p class="ql-align-center">Ưu điểm vượt trội của chân đèn&nbsp;<strong style="color: rgb(99, 99, 99);">Jinbei CK-1</strong><span style="color: rgb(99, 99, 99);">&nbsp;là Ba càng chân đỡ có thể xoay 360 độ và rất cứng chắc.<img src="https://mayanh24h.com/image/catalog/san-pham-2019/chan-may-tripod/jinbei/jinbei-ck-1-inox/jinbei-ck-1-3.jpg"></span></p><p class="ql-align-center"><span style="color: rgb(99, 99, 99);"><img src="https://mayanh24h.com/image/catalog/san-pham-2019/chan-may-tripod/jinbei/jinbei-ck-1-inox/jinbei-ck-1-4.jpg"></span></p><p><br></p>'),
